// Multi-business metrics calculation
const leadItems = $('Query Lead Status Counts').all().map(i => i.json);
const emailLogItems = $('Query Email Log (7 Days)').all().map(i => i.json);
const bizItems = $('Fetch All Businesses').all().map(i => i.json);

const leads = leadItems.flat();
const emailLogs = emailLogItems.flat();
const businesses = Array.isArray(bizItems[0]) ? bizItems[0] : bizItems;

// Build per-business metrics
const perBusinessMetrics = [];

for (const biz of businesses) {
  const bizId = biz.business_id;
  const bizUuid = biz.id;

  // Filter leads for this business
  const bizLeads = leads.filter(l => l.business_id === bizUuid || l.business_id === bizId);
  const bizLogs = emailLogs.filter(l => l.business_id === bizUuid || l.business_id === bizId);

  const statusCounts = {};
  for (const lead of bizLeads) {
    const s = lead.status || 'unknown';
    statusCounts[s] = (statusCounts[s] || 0) + 1;
  }

  const totalSent7d = bizLogs.length;
  const replied = bizLogs.filter(e => ['replied', 'positive', 'demo_booked', 'converted'].includes(e.status)).length;
  const positive = bizLogs.filter(e => ['positive', 'demo_booked', 'converted'].includes(e.status)).length;
  const demoBooked = bizLogs.filter(e => e.status === 'demo_booked' || e.status === 'converted').length;
  const converted = bizLogs.filter(e => e.status === 'converted').length;

  const byRegion = {};
  for (const log of bizLogs) {
    const region = log.region || 'unknown';
    if (!byRegion[region]) byRegion[region] = { sent: 0, replied: 0, positive: 0 };
    byRegion[region].sent++;
    if (['replied', 'positive', 'demo_booked', 'converted'].includes(log.status)) byRegion[region].replied++;
    if (['positive', 'demo_booked', 'converted'].includes(log.status)) byRegion[region].positive++;
  }

  perBusinessMetrics.push({
    business_id: bizId,
    business_name: biz.name,
    emails_sent_7d: totalSent7d,
    reply_rate: totalSent7d > 0 ? (replied / totalSent7d * 100).toFixed(1) + '%' : '0%',
    positive_rate: totalSent7d > 0 ? (positive / totalSent7d * 100).toFixed(1) + '%' : '0%',
    demo_book_rate: totalSent7d > 0 ? (demoBooked / totalSent7d * 100).toFixed(1) + '%' : '0%',
    conversion_rate: totalSent7d > 0 ? (converted / totalSent7d * 100).toFixed(1) + '%' : '0%',
    by_region: byRegion,
    lead_pipeline: statusCounts,
    total_leads: Object.values(statusCounts).reduce((a, b) => a + b, 0)
  });
}

return [{ json: { perBusinessMetrics, calculated_at: new Date().toISOString() } }];

// Upsert per-business context rows
const data = $input.first().json;
const rows = [];

for (const bm of data.perBusinessMetrics) {
  rows.push({
    json: {
      business_id: bm.business_id,
      context_key: 'email_metrics',
      context_value: JSON.stringify(bm),
      updated_at: data.calculated_at
    }
  });
}

if (rows.length === 0) {
  rows.push({ json: { business_id: 'portfolio', context_key: 'email_metrics', context_value: JSON.stringify({ message: 'No active businesses' }), updated_at: data.calculated_at } });
}

return rows;

const data = $('Calculate Metrics (Per Business)').first().json;
const metrics = data.perBusinessMetrics || [];

let report = 'Cold Email Metrics (7-Day) - Portfolio\n';
report += '======================================\n\n';

for (const bm of metrics) {
  report += '## ' + bm.business_name + ' (' + bm.business_id + ')\n';
  report += 'Sent: ' + bm.emails_sent_7d + '\n';
  report += 'Reply Rate: ' + bm.reply_rate + '\n';
  report += 'Positive Rate: ' + bm.positive_rate + '\n';
  report += 'Demo Book Rate: ' + bm.demo_book_rate + '\n';
  report += 'Conversion Rate: ' + bm.conversion_rate + '\n';
  report += 'Total Pipeline Leads: ' + bm.total_leads + '\n';

  const regionReport = Object.entries(bm.by_region || {}).map(([region, d]) => {
    return '  ' + region + ': ' + d.sent + ' sent, ' + d.replied + ' replied, ' + d.positive + ' positive';
  }).join('\n');
  report += 'By Region:\n' + (regionReport || '  No regional data') + '\n';

  const pipelineReport = Object.entries(bm.lead_pipeline || {}).map(([status, count]) => {
    return '  ' + status + ': ' + count;
  }).join('\n');
  report += 'Pipeline:\n' + (pipelineReport || '  No pipeline data') + '\n\n';
}

return [{ json: { report, ...data } }];
